// n8n webhook typeVersion 1.1 wraps POST body as { body: {...}, headers: {...} }
// All request + user fields are already in the webhook payload — no DB re-query needed.
const b = $input.first().json.body;
if (!b || !b.request_id) throw new Error('Missing request_id in webhook body.');

return {
  json: {
    request_id: b.request_id,
    user_name: b.name || 'Client',
    user_email: b.email,
    origin: b.origin,
    destination: b.destination,
    cargo_type: b.cargo_type || '',
    commodity: b.commodity || 'General Merchandise',
    cargo_specification: b.cargo_specification || '',
    packing_type: b.packing_type || 'PALLETS',
    quantity: b.quantity || 1,
    weight_kg: b.weight_kg,
    incoterms: b.incoterms || 'FOB',
    container_type: b.container_type || '',
    is_hazardous: b.is_hazardous || false,
    needs_insurance: b.needs_insurance || false,
    vessel: b.vessel || '',
    special_requirements: b.special_requirements || ''
  }
};

// Filter forwarders by specialization, then build one email object per match.
// Returns array — n8n splits array into individual items for the Gmail node.
const req = $('Code: Extract Request Data').first().json;
const cargoType = (req.cargo_type || '').toLowerCase();
const allForwarders = $input.all();

const matched = allForwarders.filter(f => {
  const specs = (f.json.specializations || '').toLowerCase();
  return specs.includes(cargoType) || specs.includes('all') || specs === '' || !f.json.specializations;
});

return matched.map(f => {
  const emailSubject = `🚢 [NEW REQUEST] ${req.request_id} — ${req.origin} → ${req.destination}`;
  const emailBody = `<!DOCTYPE html><html><head><meta charset='UTF-8'></head>
<body style="font-family:Arial,sans-serif;background:#f4f4f4;margin:0;padding:0">
<div style="max-width:600px;margin:20px auto;background:#fff;border-radius:12px;overflow:hidden;border:1px solid #e5e7eb">
  <div style="background:#1e3a5f;color:#fff;padding:32px;text-align:center">
    <h1 style="margin:0;font-size:24px;font-weight:900;letter-spacing:1px">🚢 New Freight Request</h1>
    <p style="margin:8px 0 0;opacity:0.7;font-size:13px">CargoLink Marketplace</p>
  </div>
  <div style="padding:32px">
    <div style="background:#eef4fb;border:2px solid #1e3a5f;border-radius:8px;padding:16px;text-align:center;margin-bottom:24px">
      <span style="font-family:monospace;font-size:20px;font-weight:900;color:#1e3a5f">${req.request_id}</span>
    </div>
    <p style="font-size:15px;font-weight:700;color:#111">Dear ${f.json.company_name},</p>
    <p style="color:#555;font-size:14px;line-height:1.6">A new freight request matching your profile has been posted. Only the first 3 quotations are accepted.</p>
    <div style="background:#f9f9f9;border:1px solid #e5e7eb;border-radius:10px;padding:20px;margin:20px 0">
      <table style="width:100%;border-collapse:collapse">
        <tr><td style="padding:7px 0;color:#6b7280;width:160px">Route</td><td style="font-weight:700">${req.origin} → ${req.destination}</td></tr>
        <tr><td style="padding:7px 0;color:#6b7280">Cargo Type</td><td style="font-weight:700">${req.cargo_type}</td></tr>
        <tr><td style="padding:7px 0;color:#6b7280">Commodity</td><td>${req.commodity}</td></tr>
        <tr><td style="padding:7px 0;color:#6b7280">Weight</td><td>${req.weight_kg} kg</td></tr>
        <tr><td style="padding:7px 0;color:#6b7280">Container</td><td>${req.container_type || 'TBD'}</td></tr>
        <tr><td style="padding:7px 0;color:#6b7280">Incoterms</td><td>${req.incoterms}</td></tr>
        ${req.is_hazardous ? '<tr><td colspan="2" style="color:#dc2626;font-weight:700">⚠️ Hazardous Cargo</td></tr>' : ''}
        ${req.needs_insurance ? '<tr><td colspan="2" style="color:#1d4ed8;font-weight:700">🛡️ Insurance Required</td></tr>' : ''}
      </table>
    </div>
    <div style="background:#fef3c7;border:1px solid #fcd34d;border-radius:8px;padding:16px;margin-bottom:24px">
      <p style="margin:0;color:#92400e;font-size:13px">⏰ <b>First 3 quotes only.</b> Reply to this email with your rate. Keep <b>${req.request_id}</b> in the subject line.</p>
    </div>
    <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:16px">
      <p style="margin:0;color:#166534;font-size:13px;font-weight:700">📧 Include in your reply:</p>
      <ul style="margin:8px 0 0;color:#166534;font-size:13px">
        <li>Total price (e.g. USD 2,500)</li>
        <li>Transit time in days</li>
        <li>Carrier / shipping line</li>
        <li>Quote validity (e.g. 7 days)</li>
      </ul>
    </div>
  </div>
  <div style="background:#f9fafb;padding:16px;text-align:center;font-size:11px;color:#9ca3af">CargoLink · Freight Marketplace · Automated Broadcast</div>
</div>
</body></html>`;
  return {
    json: {
      forwarder_id: f.json.forwarder_id,
      forwarder_email: f.json.email,
      forwarder_company: f.json.company_name,
      request_id: req.request_id,
      user_name: req.user_name,
      user_email: req.user_email,
      email_subject: emailSubject,
      email_body: emailBody
    }
  };
});

const req = $('Code: Extract Request Data').first().json;
const sent = $('Gmail: Send to Forwarder').all();
return {
  json: {
    request_id: req.request_id,
    user_name: req.user_name,
    user_email: req.user_email,
    total_notified: sent.length
  }
};
